package inequivalent;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

class ClonePair2799Method2Test {

    private final ClonePair2799 subject = new ClonePair2799();

    @Test
    void method2ReturnsFalseForTooShortInput() {
        // Generated by Codex (gpt-5.4).
        assertFalse(subject.method2(new byte[15]));
    }

    @Test
    void method2RecognizesValidHeader() {
        // Generated by Codex (gpt-5.4).
        byte[] data = new byte[16];
        data[0] = 0x41;
        data[2] = 0x46;
        data[3] = 0x12;

        assertTrue(subject.method2(data));
    }

    @Test
    void method2RejectsInvalidHeaderOrInvalidSyncsafeBytes() {
        // Generated by Codex (gpt-5.4).
        byte[] headerMismatch = new byte[16];
        headerMismatch[0] = 0x41;
        headerMismatch[2] = 0x45;
        headerMismatch[3] = 0x12;
        assertFalse(subject.method2(headerMismatch));

        byte[] extraBytesIgnored = new byte[16];
        extraBytesIgnored[0] = 0x41;
        extraBytesIgnored[2] = 0x46;
        extraBytesIgnored[3] = 0x12;
        extraBytesIgnored[6] = (byte) 0x80;
        assertTrue(subject.method2(extraBytesIgnored));
    }

    @Test
    void method2ThrowsNullPointerExceptionForNullInput() {
        // Generated by Codex (gpt-5.4).
        assertThrows(NullPointerException.class, () -> subject.method2(null));
    }
}
